pipeline {
    agent any

    // Triggers
    triggers { 
        pollSCM('H/5 * * * *')       // Polling SCM
        // You can also add GitHub webhook trigger via plugin
    }

    // Environment variables
    environment { 
        APP_ENV = 'dev'
        MAVEN_HOME = '/opt/maven'
    }

    // Parameters for manual build
    parameters {
        choice(name: 'ENV', choices: ['dev','stage','prod'], description: 'Select environment')
        booleanParam(name: 'RUN_TESTS', defaultValue: true, description: 'Run unit and integration tests')
    }

    options {
        buildDiscarder(logRotator(numToKeepStr: '10')) // Keep last 10 builds
        timeout(time: 60, unit: 'MINUTES')            // Max build time
        timestamps()                                  // Add timestamps in logs
    }

    stages {
        // Stage 1: Checkout
        stage('Checkout') {
            steps {
                // withCredentials([string(credentialsId: 'GITHUB_TOKEN', variable: 'TOKEN')]) {
                //     sh 'git clone https://$TOKEN@github.com/user/repo.git'
                // }
                git branch: 'main',credentialsId: 'github-creds', url: 'https://github.com/manikantatarun/mvn-app.git'
            }
        }

        // Stage 2: Build
        stage('Build') {
            steps {
                sh "${MAVEN_HOME}/bin/mvn clean package"
            }
            post {
                success {
                    archiveArtifacts artifacts: '**/target/*.jar', fingerprint: true
                }
            }
        }

        // Stage 3: Parallel Tests
        stage('Tests') {
            when { expression { params.RUN_TESTS == true } }
            parallel {
                stage('Unit Tests') {
                    steps { sh 'mvn test -Dtest=Unit*' }
                }
                stage('Integration Tests') {
                    steps { sh 'mvn test -Dtest=Integration*' }
                }
            }
        }

        // Stage 4: SonarQube Analysis
        stage('SonarQube Analysis') {
            steps {
                withSonarQubeEnv('SonarQube') {
                    sh "${MAVEN_HOME}/bin/mvn sonar:sonar"
                }
            }
        }

        // Stage 5: Deploy
        stage('Deploy') {
            agent { label 'deploy-node' } // Run deployment on a specific node
            steps {
                script {
                    if (params.ENV == 'prod') {
                        echo "Deploying to PRODUCTION environment!"
                        sh './deploy_prod.sh'
                    } else {
                        echo "Deploying to ${params.ENV} environment"
                        sh "./deploy_${params.ENV}.sh"
                    }
                }
            }
        }
    }

    // Post build actions
    post {
        always {
            echo "Cleaning up workspace"
            cleanWs()
        }
        success {
            echo "Build and Deployment Successful"
            // Example: Slack notification
            // slackSend channel: '#devops', message: "Build #${env.BUILD_NUMBER} SUCCESS"
        }
        failure {
            echo "Build/Deployment Failed, triggering rollback"
            sh './rollback.sh'
            // slackSend channel: '#devops', message: "Build #${env.BUILD_NUMBER} FAILED"
        }
    }
}
